private void xrTableCell1_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    // Get MLive_20 (male live at 20 weeks)
    decimal mLive_20 = Convert.ToDecimal(GetCurrentColumnValue("MLive_20") ?? 0);

    // Get FMTotal components (Female Mort + Female Culls)
    decimal femaleMort = Convert.ToDecimal(GetCurrentColumnValue("Female_Mort") ?? 0);
    decimal femaleCulls = Convert.ToDecimal(GetCurrentColumnValue("Female_Culls") ?? 0);
    decimal fmTotal = femaleMort + femaleCulls;

    // Get FLive_20 (female live at 20 weeks)
    decimal fLive_20 = Convert.ToDecimal(GetCurrentColumnValue("FLive_20") ?? 0);

    // Calculate if condition met
    if (mLive_20 > 0 && fLive_20 > 0)
    {
        decimal result = (fmTotal / fLive_20) * 100;
        cell.Text = result.ToString("N2") + " %";
    }
    else
    {
        cell.Text = "0.00 %";
    }
}

