private void xrTableCell13_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    // Get TotalEggs
    decimal totalEggs = Convert.ToDecimal(GetCurrentColumnValue("TotalEggs") ?? 0);

    // Get TotalFeed components (FemaleQtyKg + MaleQtyKg)
    decimal femaleQtyKg = Convert.ToDecimal(GetCurrentColumnValue("FemaleQtyKg") ?? 0);
    decimal maleQtyKg = Convert.ToDecimal(GetCurrentColumnValue("MaleQtyKg") ?? 0);
    decimal totalFeed = femaleQtyKg + maleQtyKg;

    if (totalEggs > 0)
    {
        // Calculate feed per 1000 eggs
        decimal result = (totalFeed / totalEggs) * 1000;
        cell.Text = result.ToString("N2");
    }
    else
    {
        cell.Text = "0.00";
    }
}

private void xrLabel6_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRLabel label = sender as XRLabel;

// Get HatchingEggs
decimal hatchingEggs = Convert.ToDecimal(GetCurrentColumnValue("HatchingEggs") ?? 0);

// Get TotalFeed components (FemaleQtyKg + MaleQtyKg)
decimal femaleQtyKg = Convert.ToDecimal(GetCurrentColumnValue("FemaleQtyKg") ?? 0);
decimal maleQtyKg = Convert.ToDecimal(GetCurrentColumnValue("MaleQtyKg") ?? 0);
decimal totalFeed = femaleQtyKg + maleQtyKg;

if (hatchingEggs > 0)
{
    // Calculate feed per 1000 hatching eggs
    decimal result = (totalFeed / hatchingEggs) * 1000;
    label.Text = result.ToString("N2");
}
else
{
    label.Text = "0.00";
}
}

private void xrLabel8_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRLabel label = sender as XRLabel;

    // Get FloorArea
    decimal floorArea = Convert.ToDecimal(GetCurrentColumnValue("FloorArea") ?? 0);

    // Get live birds at 20 weeks (FLive_20 + MLive_20)
    decimal fLive_20 = Convert.ToDecimal(GetCurrentColumnValue("FLive_20") ?? 0);
    decimal mLive_20 = Convert.ToDecimal(GetCurrentColumnValue("MLive_20") ?? 0);
    decimal totalLive = fLive_20 + mLive_20;

    if (floorArea > 0)
    {
        // Calculate birds per square meter
        decimal result = totalLive / floorArea;
        label.Text = result.ToString("N2");
    }
    else
    {
        label.Text = "0.00";
    }
}

private void xrLabel11_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRLabel label = sender as XRLabel;

// Get FLive_20 (female live at 20 weeks)
decimal fLive_20 = Convert.ToDecimal(GetCurrentColumnValue("FLive_20") ?? 0);

// Get FFedSpace (female feeder space)
decimal fFedSpace = Convert.ToDecimal(GetCurrentColumnValue("FFedSpace") ?? 0);

if (fLive_20 > 0)
{
    // Calculate feeder space per female bird
    decimal result = fFedSpace / fLive_20;
    label.Text = result.ToString("N2");
}
else
{
    label.Text = "0.00";
}
}

