private void xrTableCell75_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    // Get SettingEggs
    decimal settingEggs = Convert.ToDecimal(GetCurrentColumnValue("SettingEggs") ?? 0);

    // Get total chicks (DeadChicks + Culls + Broiler)
    decimal deadChicks = Convert.ToDecimal(GetCurrentColumnValue("DeadChicks") ?? 0);
    decimal culls = Convert.ToDecimal(GetCurrentColumnValue("Culls") ?? 0);
    decimal broiler = Convert.ToDecimal(GetCurrentColumnValue("Broiler") ?? 0);
    decimal totalChicks = deadChicks + culls + broiler;

    if (settingEggs > 0)
    {
        // Calculate hatchability percentage
        decimal result = (totalChicks / settingEggs) * 100;
        cell.Text = result.ToString("N2");
    }
    else
    {
        cell.Text = "0.00";
    }
}

private void xrTableCell80_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    // Get FLive_POL (female live at peak production)
    decimal fLive_POL = Convert.ToDecimal(GetCurrentColumnValue("FLive_POL") ?? 0);

    // Get total chicks (DeadChicks + Culls + Broiler)
    decimal deadChicks = Convert.ToDecimal(GetCurrentColumnValue("DeadChicks") ?? 0);
    decimal culls = Convert.ToDecimal(GetCurrentColumnValue("Culls") ?? 0);
    decimal broiler = Convert.ToDecimal(GetCurrentColumnValue("Broiler") ?? 0);
    decimal totalChicks = deadChicks + culls + broiler;

    if (fLive_POL > 0)
    {
        // Calculate chicks per hen at POL
        decimal result = totalChicks / fLive_POL;
        cell.Text = result.ToString("N2");
    }
    else
    {
        cell.Text = "0.00";
    }
}
